  ('disabled-6f0ba476-moex-00563', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司自 X1 年初起租用一建築物作為企業總部，依租約甲公司須自 X1 年起每年年初支付依市場租金水準議定之租金$500,000，租期10年，期滿 該建築物歸還予出租人。甲公司於 X1 年初按其增額借款利率 5%對該租 約認列使用權資產$4,053,911，無殘值，按直線法提列折舊。該租約對甲公 司X10年之本期淨利影響數為（不考慮所得稅，答案四捨五入至元）：', '["$(405,391)", "$(429,201)", "$(451,876)", "$(473,472)"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00564', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '承上題，惟甲公司於 X7 年底將該租約之使用權資產轉列為按公允價值衡 量之投資性不動產，該租約之使用權資產於 X7 年底之公允價值為 $1,284,255。該租約對甲公司X7年之本期淨利影響數為（不考慮所得稅， 答案四捨五入至元）：', '["$(405,391)", "$(429,201)", "$(451,876)", "$(473,472)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00565', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司採行確定福利退職後計畫，該計畫X1年期初之折現率為10%，服 務成本為$324,000，期初與期末之確定福利義務現值分別為$360,000 與 $720,000，期初與期末之計畫資產公允價值分別為$480,000 與$756,000。 若該計畫之確定福利成本均應計入淨利且經評估淨確定福利資產均無上 限，該計畫對甲公司 X1 年之本期淨利影響數為（不考慮所得稅，答案四 捨五入至元）：', '["$(240,000)", "$(312,000)", "$(320,400)", "$(324,000)"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00566', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '承上題，且經評估淨確定福利資產上限均為$0，該計畫對甲公司 X1 年之 本期淨利影響數為（不考慮所得稅，答案四捨五入至元）：', '["$(240,000)", "$(312,000)", "$(320,400)", "$(324,000)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00567', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '認列於財務報表之要素係以貨幣形式量化，因此需要選擇衡量基礎。試問 現時成本、公允價值、使用價值及履約價值等4項衡量基礎中屬進入價值 而非退出價值者有幾項？', '["1", "2", "3", "4"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00568', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '依據「財務報導之觀念架構」，下列對於科目單位之敘述何者錯誤？', '["指認列條件及衡量觀念所適用之權利或權利群組、義務或義務群組，或 權利與義務之群組", "科目單位是認列的最小層級單位，因此認列後不會再改變", "科目單位之選擇係為提供有用資訊", "於某些情況下，就認列選擇一科目單位並就衡量選擇另一科目單位，可 能係屬適當"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00569', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司12月31日公司帳上之存款餘額為$900,000。12月份之銀行對帳單 顯示12月份因存款不足而被退票為$30,000，其中$18,000又於12月底前 存入。12月底在途存款為$150,000，未兌現支票為 $144,000（包括$30,000 之支票銀行於12月20日保付）。12月16日公司誤將兌付他公司之支票 $19,800以$28,800記入公司帳上，公司尚未發現此項錯誤。12月份銀行代 收票據$60,000，並扣除代收手續費$300。試問甲公司12月31日之正確存 款餘額為何？', '["$906,000", "$938,700", "$956,700", "$986,700"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00570', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司X1 年初向乙公司承租一項特殊設備，租期5 年，租金於每年年初 支付。X5年底甲公司此項租賃相關項目餘額如下： 資產： 使用權資產 $900,000 累計折舊－使用權資產 900,000 負債： 租賃負債 $ 90,000 則關於該租賃，下列敘述何者最為可能：', '["甲公司將於X6年初以$90,000購買該設備", "該設備在X5年底的殘值為$90,000", "甲公司保證該設備在X5年底的殘值為$90,000", "該設備在X5年底的殘值較甲公司的保證金額少$90,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
